// // If A is HIGH, X outputs LOW. If A is LOW, it calculates the sum of B and C, stored in T. If T is less than D, X outputs HIGH. If T is greater than or equal to D, it then calculates T2 as the sum of E and T; if T2 is less than D, X outputs HIGH. Otherwise, X outputs LOW.
module top_module(
    input A,
    input B,
    input C,
    input D,
    input E,
    output reg X
);reg [31:0] T, T2;

    always @(*) begin
        if (A == 0) begin
            X = 0;
        end else begin
            T = B + C;
            if (T >= D) begin
                X = 1;
            end else begin
                T2 = E + T;
                if (T2 >= D) begin
                    X = 1;
                end else begin
                    X = 0;
                end
            end
        end
    end

endmodule
